<h1><?= $p?'Edit':'Add' ?> Product</h1><form method="post" enctype="multipart/form-data" class="form card"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><label>Title<input name="title" value="<?=H::e($p['title']??'') ?>" data-slug-source></label><label>Slug<input name="slug" value="<?=H::e($p['slug']??'') ?>" data-slug-target></label><label>Description<textarea name="description"><?=H::e($p['description']??'')?></textarea></label><label>Price<input type="number" step="0.01" name="price" value="<?=H::e($p['price']??'5.00')?>"></label><label>Category<select name="category_id"><option value="">None</option><?php foreach($cats as $c):?><option value="<?=$c['id']?>"><?=$c['name']?></option><?php endforeach;?></select></label><label>Tags<input name="tags" value="<?=H::e($p['tags_text']??'')?>"></label><fieldset><legend>File types</legend><?php foreach(['PNG','SVG','JPG','PDF','ZIP','Canva Template','Procreate File','Font','Other'] as $ft):?><label><input type="checkbox" name="file_types[]" value="<?=$ft?>"> <?=$ft?></label><?php endforeach;?></fieldset><label>Preview images<input type="file" disabled multiple></label><label>Protected downloadable file<input type="file" name="download"></label><p>Personal use included: always yes. Digital resale prohibited: default yes.</p><label><input type="checkbox" name="commercial_license_enabled" checked> Commercial license add-on</label><label>Commercial price<input type="number" step="0.01" name="commercial_license_price" value="<?=H::e($p['commercial_license_price']??'5.00')?>"></label><label><input type="checkbox" name="pod_allowed"> POD allowed</label><label>AI disclosure<select name="ai_disclosure" required><option>Hand Drawn</option><option>Digitally Created</option><option>AI Assisted</option><option>AI Generated</option></select></label><button name="action" value="draft">Save draft</button><button class="btn" name="action" value="review">Submit for review</button></form>
